# Prompt: Build a file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

import os
from flask import Flask, jsonify, send_from_directory, request

app = Flask(__name__)

# This should be configured for each user's root directory
# For demonstration purposes, we'll use a single root
# In a real application, this would be dynamic, e.g., user_id -> root_path
USER_ROOT_DIR = os.path.abspath('user_files')

# Ensure the root directory exists
os.makedirs(USER_ROOT_DIR, exist_ok=True)

class FileExplorerError(Exception):
    def __init__(self, message, status_code=400):
        super().__init__(message)
        self.message = message
        self.status_code = status_code

@app.errorhandler(FileExplorerError)
def handle_file_explorer_error(error):
    response = jsonify({"error": error.message})
    response.status_code = error.status_code
    return response

def _get_full_and_safe_path(relative_path):
    """
    Constructs the full path and ensures it's within the user's root directory.
    Raises FileExplorerError if the path attempts to access outside the root.
    """
    if not isinstance(relative_path, str):
        raise FileExplorerError("Path must be a string.", 400)

    # Construct the full path
    full_path = os.path.join(USER_ROOT_DIR, relative_path)

    # Normalize the path to handle '..' and clean up
    normalized_path = os.path.normpath(full_path)

    # Security check: Ensure the normalized path is still within the USER_ROOT_DIR
    # This prevents directory traversal attacks like 'user_files/../../etc/passwd'
    if not normalized_path.startswith(USER_ROOT_DIR):
        raise FileExplorerError("Access denied: Path outside user's root directory.", 403)

    # Additionally, if the root directory itself is accessed (e.g., relative_path is empty or '.'),
    # os.path.normpath might return just USER_ROOT_DIR.
    # We want to ensure that the path always refers to something *within* or *at* the root.
    # The startswith check handles most cases, but a final check for direct equality
    # when relative_path is something like '..' should also be safe if normalized_path
    # is still USER_ROOT_DIR. The key is that normalized_path must *start with* USER_ROOT_DIR.

    return normalized_path

@app.route('/list', methods=['GET'])
def list_directory():
    path = request.args.get('path', '')
    try:
        abs_path = _get_full_and_safe_path(path)

        if not os.path.exists(abs_path):
            raise FileExplorerError("Path not found.", 404)
        if not os.path.isdir(abs_path):
            raise FileExplorerError("Path is not a directory.", 400)

        items = []
        with os.scandir(abs_path) as it:
            for entry in it:
                item_info = {
                    'name': entry.name,
                    'is_directory': entry.is_dir(),
                    'is_file': entry.is_file(),
                    'size': entry.stat().st_size if entry.is_file() else None,
                    'last_modified': entry.stat().st_mtime
                }
                items.append(item_info)
        return jsonify(items)
    except FileExplorerError as e:
        raise e
    except Exception as e:
        raise FileExplorerError(f"An unexpected error occurred: {str(e)}", 500)

@app.route('/download', methods=['GET'])
def download_file():
    path = request.args.get('path')
    if not path:
        raise FileExplorerError("Missing 'path' parameter.", 400)

    try:
        abs_path = _get_full_and_safe_path(path)

        if not os.path.exists(abs_path):
            raise FileExplorerError("File not found.", 404)
        if not os.path.isfile(abs_path):
            raise FileExplorerError("Path is not a file.", 400)

        # Extract directory and filename for send_from_directory
        directory = os.path.dirname(abs_path)
        filename = os.path.basename(abs_path)

        return send_from_directory(directory, filename, as_attachment=True)
    except FileExplorerError as e:
        raise e
    except Exception as e:
        raise FileExplorerError(f"An unexpected error occurred: {str(e)}", 500)

@app.route('/info', methods=['GET'])
def get_file_info():
    path = request.args.get('path')
    if not path:
        raise FileExplorerError("Missing 'path' parameter.", 400)

    try:
        abs_path = _get_full_and_safe_path(path)

        if not os.path.exists(abs_path):
            raise FileExplorerError("Path not found.", 404)

        stat_info = os.stat(abs_path)
        info = {
            'name': os.path.basename(abs_path),
            'full_path': path, # Return the relative path requested by the user
            'is_directory': os.path.isdir(abs_path),
            'is_file': os.path.isfile(abs_path),
            'size': stat_info.st_size,
            'creation_time': stat_info.st_ctime,
            'last_modified_time': stat_info.st_mtime,
            'last_access_time': stat_info.st_atime
        }
        return jsonify(info)
    except FileExplorerError as e:
        raise e
    except Exception as e:
        raise FileExplorerError(f"An unexpected error occurred: {str(e)}", 500)

